let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let m = pt.mapping_4k();
let dom_va: bool = m.dom().contains(va);

// Pin the relevant SMT terms to common locals so both ensures-instances
// (one for r1, one for r2) line up to the same `pt`, `m`, and `dom_va`.
assert(self_.get_pagetable_by_pcid(pcid).unwrap() == pt);
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k() == m);
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va) == dom_va);

// is_Some agreement: both is_Some flags coincide because each equals `dom_va`.
assert((dom_va == r1.is_Some()) && (dom_va == r2.is_Some())
    ==> (r1.is_Some() == r2.is_Some()));

// None side: when `dom_va` is false, both `r1` and `r2` must be `None`.
assert(!dom_va && (dom_va == r1.is_Some()) && (dom_va == r2.is_Some())
    ==> (r1 is None) && (r2 is None));

// Some side: when both are Some, both ensures pin `m[va]` to
// `page_entry_to_map_entry(&r_i.unwrap())`, so the two `page_entry_to_map_entry`
// images coincide by transitivity through `m[va]`.
assert(r1.is_Some() && r2.is_Some()
    && m[va] == page_entry_to_map_entry(&r1.unwrap())
    && m[va] == page_entry_to_map_entry(&r2.unwrap())
    ==> page_entry_to_map_entry(&r1.unwrap()) == page_entry_to_map_entry(&r2.unwrap()));

// Per-field projection of `page_entry_to_map_entry` equality: equal
// `MapEntry`s force equal `addr`, `perm.write`, and `perm.execute_disable`.
assert(forall|p1: PageEntry, p2: PageEntry|
    #![trigger page_entry_to_map_entry(&p1), page_entry_to_map_entry(&p2)]
    page_entry_to_map_entry(&p1) == page_entry_to_map_entry(&p2)
        ==> p1.addr == p2.addr
            && p1.perm.write == p2.perm.write
            && p1.perm.execute_disable == p2.perm.execute_disable);

// Lift the per-field equality to the actual `r1.unwrap()`, `r2.unwrap()` pair.
assert(r1.is_Some() && r2.is_Some()
    && page_entry_to_map_entry(&r1.unwrap()) == page_entry_to_map_entry(&r2.unwrap())
    ==> r1.unwrap().addr == r2.unwrap().addr
        && r1.unwrap().perm.write == r2.unwrap().perm.write
        && r1.unwrap().perm.execute_disable == r2.unwrap().perm.execute_disable);

// Final shape of det_*_equal: case-split on `dom_va` so z3 sees both
// the is_Some-equality discriminator and (in the Some branch) the
// view-equality obligation under one structured proof.
assert(({
    &&& (dom_va == r1.is_Some())
    &&& (dom_va == r2.is_Some())
}) ==> (r1.is_Some() == r2.is_Some())) by {
    if dom_va {
    } else {
